// Calculate cognitive load based on Bloom's taxonomy levels
const bloomWeights = {
  'remember': 1,
  'understand': 2,
  'apply': 3,
  'analyze': 4,
  'evaluate': 5,
  'create': 6
};

const courseData = $fromAI('course_data', 'Course data with learning outcomes and Bloom levels', 'json');
const outcomes = courseData.learning_outcomes || [];

let totalLoad = 0;
let outcomeCount = outcomes.length;

for (const outcome of outcomes) {
  const level = outcome.bloom_level?.toLowerCase() || 'understand';
  totalLoad += bloomWeights[level] || 2;
}

const avgLoad = outcomeCount > 0 ? totalLoad / outcomeCount : 0;
const loadCategory = avgLoad < 2.5 ? 'low' : avgLoad < 4 ? 'moderate' : 'high';

return {
  total_cognitive_load: totalLoad,
  average_load: avgLoad,
  outcome_count: outcomeCount,
  load_category: loadCategory,
  is_balanced: avgLoad >= 2 && avgLoad <= 4.5
};
